using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using YourNamespace.Models;

namespace YourNamespace.Controllers
{
    public class ProductController : Controller
    {
        private ApplicationDbContext db = new ApplicationDbContext();

        // GET: Product/Details/{id}
        public ActionResult Details(int id)
        {
            var product = db.Products.Include(p => p.Reviews).FirstOrDefault(p => p.Id == id);
            if (product == null)
            {
                return HttpNotFound();
            }
            return View(product);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult LeaveReview(Review review)
        {
            if (ModelState.IsValid)
            {
                review.ProductId = Convert.ToInt32(Request.Form["ProductId"]);
                db.Reviews.Add(review);
                db.SaveChanges();
                return RedirectToAction("Details", new { id = review.ProductId });
            }
            return View(review);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                db.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}